{"command": "cd /tmp/sv-5fd30fedd4a740498092092b3a21908a/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> resolved_version
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

changes = []
unchanged = []

all_keys = sorted(set(bl.keys()) | set(al.keys()))
for key in all_keys:
    pname, fw, pid = key
    bv = bl.get(key)
    av = al.get(key)
    if bv is None:
        changes.append((pname, fw, pid, '-', av, 'Added'))
    elif av is None:
        changes.append((pname, fw, pid, bv, '-', 'Removed'))
    elif bv != av:
        changes.append((pname, fw, pid, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((pname, fw, pid, bv))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<20} {'Framework':<10} {'Package':<45} {'Before':<12} {'After':<12} Status')
    print('-' * 120)
    for c in changes:
        print(f'{c[0]:<20} {c[1]:<10} {c[2]:<45} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('No changes')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<20} {'Framework':<10} {'Package':<45} {'Version':<12}')
print('-' * 90)
for u in unchanged:
    print(f'{u[0]:<20} {u[1]:<10} {u[2]:<45} {u[3]:<12}')
"
